() => {
  let title = document.querySelector('.titleline a').textContent.trim();
  let subtext = document.querySelector('.subtext');
  let pointsMatch = subtext.textContent.match(/(\\d+) points/);
  let points = pointsMatch ? pointsMatch[1] : '0';
  let commentsMatch = subtext.textContent.match(/(\\d+) comments?/);
  let comments = commentsMatch ? commentsMatch[1] : '0';

  let topLevelComments = Array.from(document.querySelectorAll('tr.athing')).filter(tr => {
    let indent = tr.nextElementSibling.querySelector('.ind img');
    return indent && indent.width === 0;
  });
  let maxScore = -1;
  let topAuthor = '';
  topLevelComments.forEach(tr => {
    let scoreEl = tr.nextElementSibling.querySelector('.score');
    if (scoreEl) {
      let scoreText = scoreEl.textContent;
      let score = parseInt(scoreText.split(' ')[0]);
      if (score > maxScore) {
        maxScore = score;
        let authorLink = tr.nextElementSibling.querySelector('.hnuser');
        topAuthor = authorLink ? authorLink.textContent : '';
      }
    }
  });
  return {title, points, comments, topAuthor};
}

