() => {
  let titleEl = document.querySelector('.titleline a');
  let title = titleEl.textContent.trim();
  let subtextEl = titleEl.closest('tr').nextElementSibling.querySelector('td');
  let text = subtextEl.textContent;
  let pointsMatch = text.match(/(\\d+) points/);
  let points = pointsMatch ? pointsMatch[1] : '0';
  let commentsMatch = text.match(/(\\d+) comments?/);
  let comments = commentsMatch ? commentsMatch[1] : '0';

  let topLevelComments = [];
  let allComments = Array.from(document.querySelectorAll('tr.athing'));
  for (let i = 0; i < allComments.length; i++) {
    let tr = allComments[i];
    let nextTr = tr.nextElementSibling;
    if (nextTr) {
      let indent = nextTr.querySelector('.ind img');
      if (indent && indent.width === 0) {
        topLevelComments.push({tr, index: i});
      }
    }
  }

  let maxReplies = -1;
  let topAuthor = '';
  topLevelComments.forEach(({tr, index}) => {
    let replies = 0;
    for (let j = index + 1; j < allComments.length; j++) {
      let nextTr2 = allComments[j].nextElementSibling;
      if (nextTr2) {
        let indent2 = nextTr2.querySelector('.ind img');
        if (indent2) {
          if (indent2.width === 0) break;
          if (indent2.width === 40) replies++;
        }
      }
    }
    if (replies > maxReplies) {
      maxReplies = replies;
      let authorLink = tr.nextElementSibling.querySelector('.hnuser');
      topAuthor = authorLink ? authorLink.textContent : '';
    }
  });
  return {title, points, comments, topAuthor};
}

